{
  "name": "Zenith Hotel PMS",
  "description": "Sistema de gestão hoteleira simplificado para recepção, com controle de check-in, check-out, quartos e reservas.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RoomStatus {
  AVAILABLE = 'AVAILABLE',
  OCCUPIED = 'OCCUPIED',
  CLEANING = 'CLEANING',
  MAINTENANCE = 'MAINTENANCE'
}

export enum RoomType {
  SIMPLE = 'Simples',
  DOUBLE = 'Duplo',
  SUITE = 'Suíte'
}

export interface Room {
  id: string;
  number: string;
  type: RoomType;
  status: RoomStatus;
  currentGuestId?: string;
}

export interface Guest {
  id: string;
  name: string;
  document: string; // CPF/RG
  phone: string;
  email: string;
  checkInDate: string;
  checkOutDate: string;
  roomId: string;
}

export interface Reservation {
  id: string;
  guestName: string;
  date: string;
  roomId: string;
  status: 'Confirmed' | 'Pending' | 'Cancelled';
  notes: string;
}

export interface ReceptionNote {
  id: string;
  text: string;
  category: 'Request' | 'Warning' | 'Info';
  time: string;
  timestamp: number;
}

import React from 'react';
import { RoomStatus } from './types';
import { 
  CheckCircle, 
  XCircle, 
  Clock, 
  Settings, 
  LayoutDashboard, 
  Users, 
  BedDouble, 
  CalendarCheck, 
  StickyNote,
  LogOut
} from 'lucide-react';

export const STATUS_COLORS = {
  [RoomStatus.AVAILABLE]: 'bg-emerald-100 text-emerald-700 border-emerald-200',
  [RoomStatus.OCCUPIED]: 'bg-rose-100 text-rose-700 border-rose-200',
  [RoomStatus.CLEANING]: 'bg-amber-100 text-amber-700 border-amber-200',
  [RoomStatus.MAINTENANCE]: 'bg-slate-200 text-slate-700 border-slate-300'
};

export const STATUS_DOTS = {
  [RoomStatus.AVAILABLE]: 'bg-emerald-500',
  [RoomStatus.OCCUPIED]: 'bg-rose-500',
  [RoomStatus.CLEANING]: 'bg-amber-500',
  [RoomStatus.MAINTENANCE]: 'bg-slate-500'
};

export const STATUS_LABELS = {
  [RoomStatus.AVAILABLE]: 'Livre',
  [RoomStatus.OCCUPIED]: 'Ocupado',
  [RoomStatus.CLEANING]: 'Limpeza',
  [RoomStatus.MAINTENANCE]: 'Manutenção'
};

export const NAV_ITEMS = [
  { id: 'dashboard', label: 'Dashboard', icon: <LayoutDashboard size={20} /> },
  { id: 'guests', label: 'Hóspedes', icon: <Users size={20} /> },
  { id: 'rooms', label: 'Quartos', icon: <BedDouble size={20} /> },
  { id: 'reservations', label: 'Reservas', icon: <CalendarCheck size={20} /> },
  { id: 'notes', label: 'Anotações', icon: <StickyNote size={20} /> },
];

import React, { useState, useEffect } from 'react';
import { Room, Guest, Reservation, ReceptionNote, RoomStatus, RoomType } from './types';
import Login from './pages/Login';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Guests from './pages/Guests';
import Rooms from './pages/Rooms';
import Reservations from './pages/Reservations';
import Notes from './pages/Notes';

// Initial Mock Data
const INITIAL_ROOMS: Room[] = [
  { id: '1', number: '101', type: RoomType.SIMPLE, status: RoomStatus.AVAILABLE },
  { id: '2', number: '102', type: RoomType.SIMPLE, status: RoomStatus.OCCUPIED, currentGuestId: 'g1' },
  { id: '3', number: '201', type: RoomType.DOUBLE, status: RoomStatus.CLEANING },
  { id: '4', number: '202', type: RoomType.DOUBLE, status: RoomStatus.AVAILABLE },
  { id: '5', number: '301', type: RoomType.SUITE, status: RoomStatus.MAINTENANCE },
  { id: '6', number: '302', type: RoomType.SUITE, status: RoomStatus.AVAILABLE },
];

const INITIAL_GUESTS: Guest[] = [
  { 
    id: 'g1', 
    name: 'João Silva', 
    document: '123.456.789-00', 
    phone: '(11) 98888-7777', 
    email: 'joao@email.com', 
    checkInDate: '2023-10-20', 
    checkOutDate: '2023-10-25', 
    roomId: '2' 
  }
];

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentPage, setCurrentPage] = useState('dashboard');

  // App State
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [guests, setGuests] = useState<Guest[]>(INITIAL_GUESTS);
  const [reservations, setReservations] = useState<Reservation[]>([]);
  const [notes, setNotes] = useState<ReceptionNote[]>([]);

  // Persistent login for demo purposes
  useEffect(() => {
    const auth = localStorage.getItem('hotel_auth');
    if (auth === 'true') setIsAuthenticated(true);
  }, []);

  const handleLogin = (success: boolean) => {
    if (success) {
      setIsAuthenticated(true);
      localStorage.setItem('hotel_auth', 'true');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('hotel_auth');
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard rooms={rooms} guests={guests} setRooms={setRooms} setGuests={setGuests} />;
      case 'guests':
        return <Guests guests={guests} setGuests={setGuests} rooms={rooms} />;
      case 'rooms':
        return <Rooms rooms={rooms} setRooms={setRooms} />;
      case 'reservations':
        return <Reservations reservations={reservations} setReservations={setReservations} rooms={rooms} />;
      case 'notes':
        return <Notes notes={notes} setNotes={setNotes} />;
      default:
        return <Dashboard rooms={rooms} guests={guests} setRooms={setRooms} setGuests={setGuests} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        onLogout={handleLogout} 
      />
      <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50">
        <div className="max-w-7xl mx-auto">
          {renderPage()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { NAV_ITEMS } from '../constants';
import { LogOut, Hotel } from 'lucide-react';

interface SidebarProps {
  currentPage: string;
  setCurrentPage: (page: string) => void;
  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPage, setCurrentPage, onLogout }) => {
  return (
    <aside className="w-64 bg-white border-r border-slate-200 flex flex-col h-full shadow-sm">
      <div className="p-6 border-b border-slate-100 flex items-center gap-3">
        <div className="bg-blue-600 p-2 rounded-lg text-white">
          <Hotel size={24} />
        </div>
        <div>
          <h1 className="font-bold text-slate-800 tracking-tight">ZENITH HOTEL</h1>
          <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Recepção</p>
        </div>
      </div>

      <nav className="flex-1 py-6 px-4 space-y-1">
        {NAV_ITEMS.map((item) => (
          <button
            key={item.id}
            onClick={() => setCurrentPage(item.id)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group ${
              currentPage === item.id 
                ? 'bg-blue-50 text-blue-600 shadow-sm' 
                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'
            }`}
          >
            <span className={`${currentPage === item.id ? 'text-blue-600' : 'text-slate-400 group-hover:text-slate-600'}`}>
              {item.icon}
            </span>
            <span className="font-medium">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-100">
        <button
          onClick={onLogout}
          className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-rose-500 hover:bg-rose-50 transition-colors font-medium"
        >
          <LogOut size={20} />
          Sair
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { Room, Guest, RoomStatus } from '../types';
import { STATUS_COLORS, STATUS_DOTS, STATUS_LABELS } from '../constants';
import { Users, Bed, CheckSquare, XSquare, Activity } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DashboardProps {
  rooms: Room[];
  guests: Guest[];
  setRooms: React.Dispatch<React.SetStateAction<Room[]>>;
  setGuests: React.Dispatch<React.SetStateAction<Guest[]>>;
}

const Dashboard: React.FC<DashboardProps> = ({ rooms, guests }) => {
  const stats = [
    { label: 'Disponíveis', value: rooms.filter(r => r.status === RoomStatus.AVAILABLE).length, icon: <Bed />, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Ocupados', value: rooms.filter(r => r.status === RoomStatus.OCCUPIED).length, icon: <Users />, color: 'text-rose-600', bg: 'bg-rose-50' },
    { label: 'Limpeza', value: rooms.filter(r => r.status === RoomStatus.CLEANING).length, icon: <Activity />, color: 'text-amber-600', bg: 'bg-amber-50' },
    { label: 'Check-ins Hoje', value: guests.filter(g => g.checkInDate === new Date().toISOString().split('T')[0]).length, icon: <CheckSquare />, color: 'text-blue-600', bg: 'bg-blue-50' },
  ];

  const chartData = [
    { name: 'Livres', value: rooms.filter(r => r.status === RoomStatus.AVAILABLE).length, color: '#10b981' },
    { name: 'Ocupados', value: rooms.filter(r => r.status === RoomStatus.OCCUPIED).length, color: '#f43f5e' },
    { name: 'Limpeza', value: rooms.filter(r => r.status === RoomStatus.CLEANING).length, color: '#f59e0b' },
    { name: 'Manut.', value: rooms.filter(r => r.status === RoomStatus.MAINTENANCE).length, color: '#64748b' },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-2xl font-bold text-slate-800">Bem-vindo, Administrador</h2>
        <p className="text-slate-500">Aqui está o resumo do hotel para hoje.</p>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 transition-transform hover:scale-[1.02]">
            <div className={`${stat.bg} ${stat.color} p-3 rounded-xl`}>
              {React.cloneElement(stat.icon as React.ReactElement, { size: 24 })}
            </div>
            <div>
              <p className="text-sm font-medium text-slate-500 uppercase tracking-wide">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-800">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Occupancy Chart */}
        <div className="lg:col-span-1 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Status da Ocupação</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Room Status List */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold text-slate-800">Visualização Rápida dos Quartos</h3>
            <button className="text-blue-600 font-semibold text-sm hover:underline">Ver todos</button>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {rooms.map((room) => (
              <div 
                key={room.id}
                className={`p-4 rounded-xl border flex flex-col items-center justify-center gap-2 ${STATUS_COLORS[room.status]} shadow-sm`}
              >
                <span className="text-lg font-bold">{room.number}</span>
                <span className="text-[10px] font-bold uppercase tracking-widest opacity-80">{STATUS_LABELS[room.status]}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Guest, Room, RoomStatus } from '../types';
import { UserPlus, Search, Edit2, Trash2, Calendar } from 'lucide-react';

interface GuestsProps {
  guests: Guest[];
  setGuests: React.Dispatch<React.SetStateAction<Guest[]>>;
  rooms: Room[];
}

const Guests: React.FC<GuestsProps> = ({ guests, setGuests, rooms }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    document: '',
    phone: '',
    email: '',
    checkInDate: '',
    checkOutDate: '',
    roomId: ''
  });

  const filteredGuests = guests.filter(g => 
    g.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    g.document.includes(searchTerm)
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newGuest: Guest = {
      id: Math.random().toString(36).substr(2, 9),
      ...formData
    };
    setGuests([...guests, newGuest]);
    setIsModalOpen(false);
    setFormData({ name: '', document: '', phone: '', email: '', checkInDate: '', checkOutDate: '', roomId: '' });
  };

  const deleteGuest = (id: string) => {
    if (confirm('Deseja realmente remover este hóspede?')) {
      setGuests(guests.filter(g => g.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Cadastro de Hóspedes</h2>
          <p className="text-slate-500">Gerencie todos os hóspedes ativos e históricos.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 transition-all shadow-md active:scale-95"
        >
          <UserPlus size={20} />
          Novo Hóspede
        </button>
      </div>

      {/* Search bar */}
      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text" 
          placeholder="Buscar por nome ou CPF..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
        />
      </div>

      {/* Guest Table */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-sm uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4 font-semibold">Nome Completo</th>
                <th className="px-6 py-4 font-semibold">Documento</th>
                <th className="px-6 py-4 font-semibold">Quarto</th>
                <th className="px-6 py-4 font-semibold">Estadia</th>
                <th className="px-6 py-4 font-semibold">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredGuests.length > 0 ? filteredGuests.map((guest) => (
                <tr key={guest.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-semibold text-slate-800">{guest.name}</div>
                    <div className="text-xs text-slate-500">{guest.email}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{guest.document}</td>
                  <td className="px-6 py-4">
                    <span className="bg-slate-100 text-slate-700 px-3 py-1 rounded-full text-xs font-bold">
                      Quarto {rooms.find(r => r.id === guest.roomId)?.number || 'N/A'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-sm text-slate-600">
                      <Calendar size={14} />
                      {new Date(guest.checkInDate).toLocaleDateString()} - {new Date(guest.checkOutDate).toLocaleDateString()}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <button className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => deleteGuest(guest.id)}
                        className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-400 italic">
                    Nenhum hóspede encontrado.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Simple Modal Overlay */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-2xl shadow-2xl animate-in zoom-in duration-200">
            <div className="p-8">
              <h3 className="text-xl font-bold text-slate-800 mb-6">Novo Registro de Hóspede</h3>
              <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="md:col-span-2">
                  <label className="block text-sm font-bold text-slate-600 mb-2">Nome Completo</label>
                  <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">CPF / RG</label>
                  <input required type="text" value={formData.document} onChange={e => setFormData({...formData, document: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">Telefone</label>
                  <input required type="text" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">E-mail</label>
                  <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">Número do Quarto</label>
                  <select required value={formData.roomId} onChange={e => setFormData({...formData, roomId: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500">
                    <option value="">Selecione...</option>
                    {rooms.map(r => (
                      <option key={r.id} value={r.id}>Quarto {r.number} ({r.type})</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">Check-in</label>
                  <input required type="date" value={formData.checkInDate} onChange={e => setFormData({...formData, checkInDate: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-600 mb-2">Check-out</label>
                  <input required type="date" value={formData.checkOutDate} onChange={e => setFormData({...formData, checkOutDate: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div className="md:col-span-2 flex justify-end gap-3 pt-4">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-3 font-bold text-slate-500 hover:bg-slate-100 rounded-xl">Cancelar</button>
                  <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-bold shadow-lg transition-all active:scale-95">Salvar Hóspede</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Guests;

import React from 'react';
import { Room, RoomStatus } from '../types';
import { STATUS_COLORS, STATUS_LABELS } from '../constants';
import { RefreshCw, Wrench, Eraser, Check } from 'lucide-react';

interface RoomsProps {
  rooms: Room[];
  setRooms: React.Dispatch<React.SetStateAction<Room[]>>;
}

const Rooms: React.FC<RoomsProps> = ({ rooms, setRooms }) => {
  const updateStatus = (id: string, newStatus: RoomStatus) => {
    setRooms(rooms.map(r => r.id === id ? { ...r, status: newStatus } : r));
  };

  return (
    <div className="space-y-6">
      <header>
        <h2 className="text-2xl font-bold text-slate-800">Controle de Quartos</h2>
        <p className="text-slate-500">Monitore o status de limpeza e disponibilidade em tempo real.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {rooms.map((room) => (
          <div key={room.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm p-6 hover:shadow-md transition-shadow group">
